compliant:
struct Bar {
};

struct Foo {
  explicit Foo(Bar& bar); // Compliant: prevents implicit conversion
};

struct Baz {
  explicit operator Foo(); // Compliant: prevents implicit conversion
};

void func(const Foo& f);

int test(Bar& bar, Baz& baz) {
  func(Foo(bar)); // explicit conversion required
  func(static_cast<Foo>(baz)); // explicit conversion required
}

class String {
public:
  explicit String(const char* s); // Compliant: prevents implicit conversion
  String(const String& other); // Compliant: copy constructor can be non-explicit
};

void process(const String& str);

int main() {
  process(String("hello")); // explicit conversion required
}
